const $ = (selector) => document.querySelector(selector);
const $$ = (selector) => [...document.querySelectorAll(selector)];
const interviewForm = $('#interview-form');
const interviewFields = ['company', 'role', 'round_name', 'date', 'status', 'job_description', 'resume_context', 'transcript', 'personal_notes'];
const app = { selectedId: null, current: null, interviews: [], resumes: [], research: [], researchCandidates: [], resumeId: '', jdAnalysis: null, selectedAudio: null, selectedResumeFile: null, editingResumeId: null, editingResearchId: null, pendingResearchMeta: null, noteQuestions: [] };
const ACCESS_TOKEN_KEY = 'autumn-assistant-access-token';

async function api(url, options = {}) {
  const response = await fetch(url, { headers: { 'Content-Type': 'application/json', ...accessHeaders(), ...(options.headers || {}) }, ...options });
  const data = await response.json();
  if (response.status === 401) throw Error('需要访问口令。');
  if (!response.ok || !data.ok) throw Error(data.error || '请求没有完成。');
  return data;
}
function accessHeaders() { const token = sessionStorage.getItem(ACCESS_TOKEN_KEY); return token ? { 'X-App-Token': token } : {}; }
function toast(message) { const box = $('#toast'); box.textContent = message; box.hidden = false; clearTimeout(toast.timer); toast.timer = setTimeout(() => box.hidden = true, 5000); }
function busy(button, isBusy, label) { button.disabled = isBusy; button.textContent = isBusy ? label : button.dataset.label; }
function field(name) { return interviewForm.elements.namedItem(name); }
function setView(viewId) { $$('.view').forEach(view => view.classList.toggle('active', view.id === viewId)); $$('.nav-button').forEach(button => button.classList.toggle('active', button.dataset.view === viewId)); const titles = { 'review-view': '面试复盘', 'research-view': '面经资料库', 'growth-view': '阶段成长报告', 'resume-view': '简历库' }; $('#page-title').textContent = viewId === 'review-view' && app.current ? `${app.current.company} · ${app.current.role}` : titles[viewId]; $('#top-eyebrow').textContent = viewId === 'review-view' ? 'INTERVIEW REVIEW WORKSPACE · V3' : 'AUTUMN PM COACH · V3'; }
function interviewPayload() { const data = Object.fromEntries(interviewFields.map(name => [name, field(name).value])); const resume = app.resumes.find(item => item.id === app.resumeId); return { ...data, resume_id: app.resumeId, resume_name: resume?.name || app.current?.resume_name || '', jd_analysis: app.jdAnalysis, research_context: app.researchCandidates }; }

function renderInterviewList() { const list = $('#interview-list'); list.replaceChildren(); $('#interview-total').textContent = app.interviews.length; if (!app.interviews.length) { list.innerHTML = '<p class="empty-copy">还没有面试档案。</p>'; return; } app.interviews.forEach(item => { const button = document.createElement('button'); button.type = 'button'; button.className = `interview-item ${item.id === app.selectedId ? 'active' : ''}`; button.innerHTML = `<strong></strong><span></span>`; button.querySelector('strong').textContent = `${item.company} · ${item.role}`; button.querySelector('span').textContent = `${item.round_name || '面试'} · ${item.date || '未填写日期'}${item.has_review ? ' · 已复盘' : ''}`; button.onclick = () => loadInterview(item.id); list.append(button); }); }
function renderMetrics() { $('#metric-total').textContent = app.interviews.length; $('#metric-actions').textContent = app.interviews.reduce((sum, item) => sum + item.open_actions, 0); $('#metric-reviews').textContent = app.interviews.filter(item => item.has_review).length; const usable = app.research.filter(item => ['approved', 'auto_approved'].includes(item.status)).length; $('#metric-research').textContent = usable; $('#research-nav-count').textContent = usable; }
async function refreshInterviews() { app.interviews = (await api('/api/interviews')).interviews; renderInterviewList(); renderMetrics(); }
async function refreshResumes() { app.resumes = (await api('/api/resumes')).resumes; const select = $('#resume-select'); const old = app.resumeId; select.replaceChildren(new Option('暂不关联简历', '')); app.resumes.forEach(item => select.add(new Option(`${item.name}${item.target_role ? ' · ' + item.target_role : ''}`, item.id))); select.value = old; renderResumeList(); }
async function refreshResearch() { const data = await api('/api/research'); app.research = data.research; $('#research-total').textContent = data.stats.total; $('#research-usable').textContent = data.stats.usable; $('#research-review').textContent = data.stats.needs_review; renderResearchList(); renderMetrics(); }

function resetInterview() { app.selectedId = null; app.current = null; app.resumeId = ''; app.jdAnalysis = null; app.researchCandidates = []; app.selectedAudio = null; app.noteQuestions = []; renderNoteQuestions([]); interviewFields.forEach(name => field(name).value = name === 'status' ? '待复盘' : ''); $('#resume-select').value = ''; $('#resume-preview').textContent = '选择一份简历；保存面试时会记录当时的内容快照。'; $('#jd-analysis').hidden = true; $('#jd-research-handoff').hidden = true; $('#audio-state').textContent = '尚未选择录音'; $('#consent-check').checked = false; $('#page-title').textContent = '新建一场面试复盘'; setSaveState('未保存'); setReviewState('等待资料'); renderReview(null); renderInterviewList(); setView('review-view'); }
function setSaveState(text, kind = '') { $('#save-state').textContent = text; $('#save-state').className = `save-state ${kind}`; }
function setReviewState(text, kind = '') { $('#review-state').textContent = text; $('#review-state').className = `review-state ${kind}`; }
function fillInterview(record) { interviewFields.forEach(name => field(name).value = record?.[name] || ''); app.resumeId = record?.resume_id || ''; app.researchCandidates = record?.research_context || []; $('#resume-select').value = app.resumeId; app.jdAnalysis = record?.jd_analysis || null; renderJd(); renderJdResearch({ candidates: app.researchCandidates, search_meta: app.researchCandidates.length ? { result_count: app.researchCandidates.length, platform_label: '已保存线索' } : null }); $('#resume-preview').textContent = record?.resume_name ? `已关联：${record.resume_name}。此场面试已保存当时的简历快照。` : '暂未关联简历。'; }
async function loadInterview(id) { try { app.current = (await api(`/api/interviews/${id}`)).interview; app.selectedId = id; fillInterview(app.current); $('#page-title').textContent = `${app.current.company} · ${app.current.role}`; setSaveState('已保存', 'saved'); setReviewState(app.current.review ? '已生成' : '等待复盘', app.current.review ? 'ready' : ''); renderReview(app.current.review); renderInterviewList(); setView('review-view'); } catch (error) { toast(error.message); } }
async function saveInterview() { const button = $('#save-button'); busy(button, true, '正在保存...'); try { const data = app.selectedId ? await api(`/api/interviews/${app.selectedId}`, { method: 'PUT', body: JSON.stringify(interviewPayload()) }) : await api('/api/interviews', { method: 'POST', body: JSON.stringify(interviewPayload()) }); app.selectedId = data.interview.id; app.current = data.interview; $('#page-title').textContent = `${app.current.company} · ${app.current.role}`; setSaveState('已保存', 'saved'); await refreshInterviews(); return app.current; } finally { busy(button, false, ''); } }

function reviewSection(title) { const section = document.createElement('section'); section.className = 'review-section'; const heading = document.createElement('h4'); heading.textContent = title; section.append(heading); return section; }
function renderCoachItems(root, title, items, detailKey) { if (!items?.length) return; const section = reviewSection(title); const grid = document.createElement('div'); grid.className = 'coach-grid'; items.forEach(item => { const card = document.createElement('article'); card.className = 'coach-item'; card.innerHTML = '<strong></strong><p class="evidence"></p><p class="detail"></p>'; card.querySelector('strong').textContent = item.title || '观察项'; card.querySelector('.evidence').textContent = `证据：${item.evidence || '未提供'}`; card.querySelector('.detail').textContent = item[detailKey] || ''; grid.append(card); }); section.append(grid); root.append(section); }
function renderReview(review) { const root = $('#review-content'); root.replaceChildren(); root.hidden = !review; $('#review-empty').hidden = !!review; if (!review) return; const summary = document.createElement('div'); summary.className = 'review-summary'; summary.textContent = review.summary || ''; root.append(summary); renderCoachItems(root, '表现亮点', review.strengths, 'why_it_worked'); renderCoachItems(root, '需要补强', review.gaps, 'improvement'); if (review.skill_diagnosis?.length) { const section = reviewSection('PM 能力诊断'); const grid = document.createElement('div'); grid.className = 'skill-score-grid'; review.skill_diagnosis.forEach(skill => { const card = document.createElement('article'); card.className = 'skill-score'; card.innerHTML = '<div><strong></strong><span></span></div><p class="evidence"></p><p></p><p class="next"></p>'; card.querySelector('strong').textContent = skill.skill_name || skill.skill_id || 'PM 能力'; card.querySelector('span').textContent = `${skill.score}/5`; card.querySelector('.evidence').textContent = `证据：${skill.evidence || '未提供'}`; card.querySelectorAll('p')[1].textContent = skill.diagnosis || ''; card.querySelector('.next').textContent = `练习：${skill.next_practice || ''}`; grid.append(card); }); section.append(grid); root.append(section); } if (review.questions?.length) { const section = reviewSection('逐题复盘'); const list = document.createElement('div'); list.className = 'question-list'; review.questions.forEach(question => { const card = document.createElement('article'); card.className = 'question-item'; card.innerHTML = '<div class="question-top"><strong></strong><span class="score"></span></div><p class="answer"></p><p class="evidence"></p><p class="assessment"></p><p class="next"></p>'; card.querySelector('strong').textContent = question.question; card.querySelector('.score').textContent = `${question.score}/5`; card.querySelector('.answer').textContent = question.answer_summary || ''; card.querySelector('.evidence').textContent = `证据：${question.evidence || ''}`; card.querySelector('.assessment').textContent = question.assessment || ''; card.querySelector('.next').textContent = `练习：${question.next_practice || ''}`; list.append(card); }); section.append(list); root.append(section); } if (review.action_plan?.length) { const section = reviewSection('下一步行动'); const list = document.createElement('div'); list.className = 'action-list'; review.action_plan.forEach(action => { const row = document.createElement('label'); row.className = `action-item ${action.done ? 'done' : ''}`; row.innerHTML = '<input type="checkbox" /><div><strong></strong><span></span></div><b></b>'; const checkbox = row.querySelector('input'); checkbox.checked = !!action.done; checkbox.onchange = () => toggleAction(action.id, checkbox.checked); row.querySelector('strong').textContent = action.action; row.querySelector('span').textContent = action.reason; row.querySelector('b').textContent = action.priority || '中'; list.append(row); }); section.append(list); root.append(section); } if (review.follow_up) { const section = reviewSection('后续建议'); const text = document.createElement('div'); text.className = 'follow-up'; text.textContent = review.follow_up; section.append(text); root.append(section); } }
function renderScoreSummary(review) {
  const summary = review.score_summary || {};
  const quality = review.review_quality || {};
  const card = document.createElement('section');
  card.className = 'score-summary';
  card.innerHTML = '<div class="score-summary-main"><span class="eyebrow">COACHING SIGNAL</span><strong></strong><span></span></div><div class="score-summary-stats"><div><span>证据覆盖</span><strong></strong></div><div><span>诊断置信度</span><strong></strong></div><div><span>训练阶段</span><strong></strong></div></div><p class="score-summary-note"></p>';
  card.querySelector('.score-summary-main strong').textContent = summary.coach_score != null ? `${summary.coach_score}/100` : '待生成';
  card.querySelector('.score-summary-main span:last-child').textContent = summary.training_band || '训练信号';
  card.querySelector('.score-summary-stats div:nth-child(1) strong').textContent = `${Math.round((quality.evidence_coverage || 0) * 100)}%`;
  card.querySelector('.score-summary-stats div:nth-child(2) strong').textContent = quality.confidence || '未知';
  card.querySelector('.score-summary-stats div:nth-child(3) strong').textContent = summary.priority_skills?.length ? `优先补强 ${summary.priority_skills.length} 项` : '暂无优先项';
  card.querySelector('.score-summary-note').textContent = quality.data_quality || '评分仅用于训练优先级，不代表录用判断。';
  return card;
}

function renderSkillCard(skill) {
  const card = document.createElement('article');
  card.className = 'skill-score';
  card.innerHTML = '<div class="skill-score-head"><div><strong></strong><small></small></div><span></span></div><p class="evidence"></p><p class="skill-diagnosis-copy"></p><div class="evidence-profile"></div><details><summary>展开评分依据</summary><div class="dimension-list"></div><div class="skill-gap-list"></div><div class="practice-plan"></div></details>';
  card.querySelector('.skill-score-head strong').textContent = skill.skill_name || skill.skill_id || 'PM 能力';
  card.querySelector('.skill-score-head small').textContent = `${skill.confidence || '未知'} 置信度 · 覆盖 ${Math.round((skill.evidence_coverage || 0) * 100)}%`;
  card.querySelector('.skill-score-head > span').textContent = `${skill.score}/5`;
  card.querySelector('.evidence').textContent = `证据：${skill.evidence || '未提供'}`;
  card.querySelector('.skill-diagnosis-copy').textContent = skill.diagnosis || '暂无诊断。';
  const profileLabels = { specificity: '具体性', ownership: '个人归因', causality: '因果验证', result_quality: '结果质量', reflection: '复盘迁移', probe_resilience: '追问韧性' };
  card.querySelector('.evidence-profile').textContent = `证据剖面：${Object.entries(profileLabels).map(([key, label]) => `${label} ${skill.evidence_profile?.[key] ?? 0}/3`).join(' · ')}`;
  const dimensions = card.querySelector('.dimension-list');
  (skill.dimensions || []).forEach(dimension => {
    const row = document.createElement('div');
    row.className = 'dimension-row';
    row.innerHTML = '<div><strong></strong><span></span></div><p></p><small></small>';
    row.querySelector('strong').textContent = dimension.label || dimension.id;
    row.querySelector('span').textContent = dimension.score == null ? '未展示' : `${dimension.score}/5`;
    row.querySelector('p').textContent = `状态：${dimension.status || 'unknown'} · ${dimension.rationale || ''}`;
    row.querySelector('small').textContent = `证据：${dimension.evidence || '未提供'}`;
    dimensions.append(row);
  });
  const gaps = card.querySelector('.skill-gap-list');
  (skill.gaps || []).forEach(gap => {
    const item = document.createElement('p');
    item.textContent = `缺口 ${gap.severity || 'medium'}：${gap.impact || gap.gap_id} · 证据：${gap.evidence || '未提供'}`;
    gaps.append(item);
  });
  const plan = skill.practice_plan || {};
  if (plan.action || plan.prompt || plan.success_criteria?.length) {
    const practice = card.querySelector('.practice-plan');
    practice.innerHTML = '<strong>下一步训练</strong><p></p><ul></ul><small></small>';
    practice.querySelector('p').textContent = plan.prompt ? `${plan.action || '训练'}：${plan.prompt}` : (plan.action || skill.next_practice || '补充一轮练习');
    (plan.success_criteria || []).forEach(item => { const li = document.createElement('li'); li.textContent = item; practice.querySelector('ul').append(li); });
    practice.querySelector('small').textContent = plan.follow_up_question ? `下一条追问：${plan.follow_up_question}` : '';
  }
  return card;
}

function renderReview(review) {
  const root = $('#review-content'); root.replaceChildren(); root.hidden = !review; $('#review-empty').hidden = !!review; if (!review) return;
  root.append(renderScoreSummary(review));
  const summary = document.createElement('div'); summary.className = 'review-summary'; summary.textContent = review.summary || ''; root.append(summary);
  renderCoachItems(root, '表现亮点', review.strengths, 'why_it_worked'); renderCoachItems(root, '需要补强', review.gaps, 'improvement');
  if (review.skill_diagnosis?.length) { const section = reviewSection('PM 能力诊断'); const grid = document.createElement('div'); grid.className = 'skill-score-grid'; review.skill_diagnosis.forEach(skill => grid.append(renderSkillCard(skill))); section.append(grid); root.append(section); }
  if (review.questions?.length) { const section = reviewSection('逐题复盘'); const list = document.createElement('div'); list.className = 'question-list'; review.questions.forEach(question => { const card = document.createElement('article'); card.className = 'question-item'; card.innerHTML = '<div class="question-top"><strong></strong><span class="score"></span></div><p class="answer"></p><p class="evidence"></p><p class="assessment"></p><p class="question-meta"></p><p class="next"></p>'; card.querySelector('strong').textContent = question.question; card.querySelector('.score').textContent = `${question.score}/5`; card.querySelector('.answer').textContent = question.answer_summary || ''; card.querySelector('.evidence').textContent = `证据：${question.evidence || ''}`; card.querySelector('.assessment').textContent = question.assessment || ''; card.querySelector('.question-meta').textContent = `证据状态：${question.evidence_quality || 'unknown'}${question.skills?.length ? ` · 能力：${question.skills.join('、')}` : ''}`; card.querySelector('.next').textContent = `练习：${question.next_practice || ''}`; list.append(card); }); section.append(list); root.append(section); }
  if (review.action_plan?.length) { const section = reviewSection('下一步行动'); const list = document.createElement('div'); list.className = 'action-list'; review.action_plan.forEach(action => { const row = document.createElement('label'); row.className = `action-item ${action.done ? 'done' : ''}`; row.innerHTML = '<input type="checkbox" /><div><strong></strong><span></span></div><b></b>'; const checkbox = row.querySelector('input'); checkbox.checked = !!action.done; checkbox.onchange = () => toggleAction(action.id, checkbox.checked); row.querySelector('strong').textContent = action.action; row.querySelector('span').textContent = action.reason; row.querySelector('b').textContent = action.priority || '中'; list.append(row); }); section.append(list); root.append(section); }
  if (review.follow_up) { const section = reviewSection('后续建议'); const text = document.createElement('div'); text.className = 'follow-up'; text.textContent = review.follow_up; section.append(text); root.append(section); }
}

async function toggleAction(id, done) { try { app.current = (await api(`/api/interviews/${app.selectedId}/actions/${id}`, { method: 'PATCH', body: JSON.stringify({ done }) })).interview; renderReview(app.current.review); await refreshInterviews(); } catch (error) { toast(error.message); } }
function renderJd() { const root = $('#jd-analysis'); root.replaceChildren(); if (!app.jdAnalysis) { root.hidden = true; return; } root.hidden = false; const title = document.createElement('strong'); title.textContent = app.jdAnalysis.role_title || '岗位画像'; root.append(title); [['职责', 'responsibilities'], ['要求', 'requirements'], ['关键词', 'keywords'], ['可能追问', 'interview_focus'], ['搜索主题', 'search_topics']].forEach(([label, key]) => { if (!app.jdAnalysis[key]?.length) return; const group = document.createElement('div'); group.innerHTML = '<span></span><ul></ul>'; group.querySelector('span').textContent = label; app.jdAnalysis[key].forEach(item => { const li = document.createElement('li'); li.textContent = item; group.querySelector('ul').append(li); }); root.append(group); }); }
function renderJdResearch(data) { const root = $('#jd-research-handoff'); if (!root) return; const candidates = data?.candidates || []; root.hidden = !candidates.length; if (!candidates.length) return; root.querySelector('strong').textContent = `已按 JD 自动发现 ${candidates.length} 条面经线索`; root.querySelector('span').textContent = 'Agent 已自动规划查询并尝试读取公开页面；自动读取结果仍需来源确认后才可作为证据。'; }
async function autoIngestResearchCandidates(candidates) { await Promise.all((candidates || []).slice(0, 8).map(async candidate => { try { await api('/api/research/candidate', { method: 'POST', body: JSON.stringify({ candidate }) }); } catch (error) { if (!/只读|访问口令|写入/.test(error.message)) throw error; } })); await refreshResearch(); }
async function autoSearchFromJd(raw, analysis) { const topic = [...(analysis.search_topics || []), ...(analysis.search_synonyms || []), ...(analysis.interview_focus || []), ...(analysis.keywords || [])].slice(0, 10).join(' '); const payload = { company: field('company').value, role: field('role').value || analysis.role_title || '产品经理', round_name: field('round_name').value, topic, job_description: raw, jd_analysis: analysis, platform: $('#discover-platform')?.value || 'all' }; const data = await api('/api/research/agent', { method: 'POST', body: JSON.stringify(payload) }); app.researchCandidates = data.collected || []; renderSearchMeta(data.search_meta); renderAgentTrace(data.trace, data.stop_reason, data.found_enough); renderJdResearch({ ...data, candidates: app.researchCandidates }); renderDiscovery(app.researchCandidates); await autoIngestResearchCandidates(app.researchCandidates); }
async function extractJd() { const raw = field('job_description').value.trim(); if (raw.length < 30) { toast('请先粘贴一段足够完整的 JD。'); return; } const button = $('#extract-jd'); busy(button, true, '正在解析并搜索...'); try { app.jdAnalysis = (await api('/api/extract-jd', { method: 'POST', body: JSON.stringify({ job_description: raw }) })).analysis; if (!field('role').value && app.jdAnalysis.role_title) field('role').value = app.jdAnalysis.role_title; renderJd(); setSaveState('JD 已解析'); try { await autoSearchFromJd(raw, app.jdAnalysis); toast('已按 JD 自动识别并收录面经候选；问题生成会引用这些线索。'); } catch (error) { renderJdResearch({ candidates: [] }); toast(`JD 已解析，但自动搜索未完成：${error.message}`); } } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
async function transcribe() { if (!app.selectedAudio) { toast('请先选择一段录音。'); return; } if (!$('#consent-check').checked) { toast('转写前，请确认你有权使用这段录音。'); return; } const button = $('#transcribe-audio'); const data = new FormData(); data.append('audio', app.selectedAudio); data.append('consent', 'true'); busy(button, true, 'Gemini 正在转写...'); $('#audio-state').textContent = '正在上传并转写，时间取决于录音长度...'; try { const response = await fetch('/api/transcribe', { method: 'POST', body: data, headers: accessHeaders() }); const result = await response.json(); if (!response.ok || !result.ok) throw Error(result.error || '转写失败'); field('transcript').value = result.transcription.transcript; $('#audio-state').textContent = `已转写${result.transcription.language ? ' · ' + result.transcription.language : ''}${result.transcription.notes ? ' · ' + result.transcription.notes : ''}`; setSaveState('有未保存修改'); } catch (error) { $('#audio-state').textContent = '转写失败'; toast(error.message); } finally { busy(button, false, ''); } }
async function reviewInterview() { if (!$('#consent-check').checked) { toast('生成复盘前，请确认你有权使用这份面试材料。'); return; } const button = $('#review-button'); busy(button, true, 'Gemini 正在复盘...'); setReviewState('正在分析证据', 'running'); try { const record = await saveInterview(); app.current = (await api(`/api/interviews/${record.id}/review`, { method: 'POST', body: '{}' })).interview; fillInterview(app.current); renderReview(app.current.review); setReviewState('已生成', 'ready'); await refreshInterviews(); } catch (error) { setReviewState('生成失败'); toast(error.message); } finally { busy(button, false, ''); } }

const NOTE_TYPE_CLASS = { '命中': 'hit', '补刀': 'gap', '通用': 'common' };
async function generateNoteQuestions() { const button = $('#note-questions'); busy(button, true, '正在出题...'); try { const payload = { company: field('company').value, role: field('role').value, job_description: field('job_description').value, resume_context: field('resume_context').value, jd_analysis: app.jdAnalysis, research_context: app.researchCandidates, interview_id: app.selectedId || '' }; const data = await api('/api/note-questions', { method: 'POST', body: JSON.stringify(payload) }); app.noteQuestions = data.questions || []; renderNoteQuestions(app.noteQuestions); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
function renderNoteQuestions(questions) { const panel = $('#note-questions-panel'); panel.replaceChildren(); panel.hidden = !questions.length; if (!questions.length) return; questions.forEach(q => { const card = document.createElement('article'); card.className = 'note-question'; card.dataset.id = q.id; card.innerHTML = '<div class="note-question-head"><span class="note-badge"></span><strong></strong></div><p class="note-why"></p><textarea rows="2" placeholder="趁记忆新鲜，简短记下..."></textarea>'; const badge = card.querySelector('.note-badge'); badge.textContent = q.type || '问题'; badge.classList.add(NOTE_TYPE_CLASS[q.type] || 'common'); card.querySelector('strong').textContent = q.question; const basis = q.research_basis?.length ? ` · 公开线索：${q.research_basis.join('、')}` : ''; card.querySelector('.note-why').textContent = q.why_asked ? `为什么问：${q.why_asked}${basis}` : basis; panel.append(card); }); const actions = document.createElement('div'); actions.className = 'note-questions-actions'; const merge = document.createElement('button'); merge.type = 'button'; merge.className = 'secondary-button compact-button'; merge.textContent = '把问答整理进转写'; merge.onclick = collectNoteAnswersIntoTranscript; actions.append(merge); panel.append(actions); }
function collectNoteAnswersIntoTranscript() { const blocks = []; $$('#note-questions-panel .note-question').forEach(card => { const answer = card.querySelector('textarea').value.trim(); if (!answer) return; const question = card.querySelector('strong').textContent; blocks.push(`Q: ${question}\nA: ${answer}`); }); if (!blocks.length) { toast('先填写至少一个回答，再并入转写。'); return; } const transcript = field('transcript'); const addition = `【面后速记】\n${blocks.join('\n\n')}`; transcript.value = transcript.value.trim() ? `${transcript.value.trim()}\n\n${addition}` : addition; setSaveState('有未保存修改'); toast('已并入转写，可继续补充或生成复盘。'); }


function renderResumeList() { const list = $('#resume-list'); list.replaceChildren(); if (!app.resumes.length) { list.innerHTML = '<p class="empty-copy">还没有简历版本。</p>'; return; } app.resumes.forEach(item => { const button = document.createElement('button'); button.type = 'button'; button.className = `interview-item ${item.id === app.editingResumeId ? 'active' : ''}`; button.innerHTML = '<strong></strong><span></span>'; button.querySelector('strong').textContent = item.name; button.querySelector('span').textContent = item.target_role || '未填写目标岗位'; button.onclick = () => loadResume(item.id); list.append(button); }); }
function resetResume() { app.editingResumeId = null; app.selectedResumeFile = null; ['resume-name', 'resume-target', 'resume-content'].forEach(id => $(`#${id}`).value = ''); $('#resume-file').value = ''; $('#resume-file-consent').checked = false; $('#resume-file-state').textContent = '尚未选择文件'; renderResumeList(); }
async function loadResume(id) { try { const resume = (await api(`/api/resumes/${id}`)).resume; app.editingResumeId = id; $('#resume-name').value = resume.name; $('#resume-target').value = resume.target_role; $('#resume-content').value = resume.content; renderResumeList(); setView('resume-view'); } catch (error) { toast(error.message); } }
async function saveResume() { const button = $('#save-resume'); busy(button, true, '正在保存...'); try { const payload = { name: $('#resume-name').value, target_role: $('#resume-target').value, content: $('#resume-content').value }; const data = app.editingResumeId ? await api(`/api/resumes/${app.editingResumeId}`, { method: 'PUT', body: JSON.stringify(payload) }) : await api('/api/resumes', { method: 'POST', body: JSON.stringify(payload) }); app.editingResumeId = data.resume.id; await refreshResumes(); app.resumeId = data.resume.id; $('#resume-select').value = app.resumeId; $('#resume-preview').textContent = `已关联：${data.resume.name}。保存面试时会记录当时的内容快照。`; renderResumeList(); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
async function selectResume() { app.resumeId = $('#resume-select').value; if (!app.resumeId) { field('resume_context').value = ''; $('#resume-preview').textContent = '暂未关联简历。'; return; } try { const resume = (await api(`/api/resumes/${app.resumeId}`)).resume; field('resume_context').value = resume.content; $('#resume-preview').textContent = `已关联：${resume.name}。保存面试时会记录当时的内容快照。`; setSaveState('有未保存修改'); } catch (error) { toast(error.message); } }
async function parseResumeFile() { if (!app.selectedResumeFile) { toast('请先选择 PDF 或图片简历。'); return; } if (!$('#resume-file-consent').checked) { toast('解析前，请确认同意将文件发送给 Gemini。'); return; } const button = $('#parse-resume-file'); const data = new FormData(); data.append('resume', app.selectedResumeFile); data.append('consent', 'true'); busy(button, true, 'Gemini 正在解析...'); $('#resume-file-state').textContent = '正在上传并解析简历文件...'; try { const response = await fetch('/api/resumes/parse', { method: 'POST', body: data, headers: accessHeaders() }); const result = await response.json(); if (!response.ok || !result.ok) throw Error(result.error || '简历解析失败'); $('#resume-name').value = result.resume.name; $('#resume-target').value = result.resume.target_role; $('#resume-content').value = result.resume.content; $('#resume-file-state').textContent = '解析完成，请检查并保存为新版本。'; } catch (error) { $('#resume-file-state').textContent = '解析失败'; toast(error.message); } finally { busy(button, false, ''); } }

function researchPayload() { return { title: $('#research-title').value, url: $('#research-url').value, platform: $('#research-platform').value, company: $('#research-company').value, role: $('#research-role').value, round_name: $('#research-round').value, published_date: $('#research-date').value, tags: $('#research-tags').value, source_text: $('#research-source').value, comments_text: $('#research-comments').value, notes: $('#research-notes').value, ...(app.pendingResearchMeta || {}) }; }
function setResearchState(text, kind = '') { $('#research-state').textContent = text; $('#research-state').className = `save-state ${kind}`; }
function resetResearch() { app.editingResearchId = null; app.pendingResearchMeta = null; ['research-title', 'research-url', 'research-company', 'research-round', 'research-date', 'research-tags', 'research-source', 'research-comments', 'research-notes'].forEach(id => $(`#${id}`).value = ''); $('#research-platform').value = '牛客'; $('#research-role').value = '产品经理'; setResearchState('新资料'); renderResearchList(); }
function fillResearch(record) { app.editingResearchId = record.id; app.pendingResearchMeta = { platform_id: record.platform_id || '', search_query: record.search_query || '', source_kind: record.source_kind || '', provenance_status: record.provenance_status || '', retrieved_at: record.retrieved_at || '' }; $('#research-title').value = record.title || ''; $('#research-url').value = record.url || ''; $('#research-platform').value = record.platform || '其他'; $('#research-company').value = record.company || ''; $('#research-role').value = record.role || ''; $('#research-round').value = record.round_name || ''; $('#research-date').value = record.published_date || ''; $('#research-tags').value = record.tags || ''; $('#research-source').value = record.source_text || ''; $('#research-comments').value = record.comments_text || ''; $('#research-notes').value = record.notes || ''; setResearchState(record.status === 'candidate' ? '待摘录原文' : '已入库', record.status === 'candidate' ? '' : 'saved'); }
function statusLabel(status) { return ({ candidate: '待摘录原文', auto_approved: 'AI 可用', needs_review: '待确认', approved: '已确认', dismissed: '不使用' })[status] || '未知'; }
function renderResearchList() { const list = $('#research-list'); list.replaceChildren(); if (!app.research.length) { list.innerHTML = '<p class="empty-copy">还没有公开资料。先搜索候选，再摘录原帖正文进行 AI 预审。</p>'; return; } app.research.forEach(record => { const card = document.createElement('article'); card.className = 'research-item'; const assessment = record.assessment || {}; card.innerHTML = '<div class="research-top"><div><a target="_blank" rel="noreferrer"></a><p></p></div><div class="badge-row"><span class="status-badge"></span><span class="confidence"></span></div></div><p class="research-summary"></p><div class="research-meta"></div><div class="research-actions"></div>'; const link = card.querySelector('a'); link.href = record.url; link.textContent = record.title; card.querySelector('.research-top p').textContent = [record.platform, record.company, record.role, record.round_name, record.published_date].filter(Boolean).join(' · '); const badge = card.querySelector('.status-badge'); badge.textContent = statusLabel(record.status); badge.classList.add(record.status); card.querySelector('.confidence').textContent = record.assessment ? `AI 置信度 ${record.confidence}%` : '尚未预审'; card.querySelector('.research-summary').textContent = assessment.summary || (record.source_text || '').slice(0, 240) || '未填写摘要'; card.querySelector('.research-meta').textContent = assessment.concerns?.length ? `限制：${assessment.concerns.join('；')}` : '资料仅作为公开经验参考，复盘中会保留原链接与日期。'; const actions = card.querySelector('.research-actions'); const edit = document.createElement('button'); edit.className = 'secondary-button compact-button'; edit.textContent = '查看/编辑'; edit.onclick = () => { fillResearch(record); setView('research-view'); window.scrollTo({ top: 0, behavior: 'smooth' }); }; actions.append(edit); if (record.status === 'needs_review') { const approve = document.createElement('button'); approve.className = 'secondary-button compact-button'; approve.textContent = '确认可用'; approve.onclick = () => updateResearchStatus(record.id, 'approved'); actions.append(approve); } if (record.status !== 'dismissed') { const dismiss = document.createElement('button'); dismiss.className = 'text-button'; dismiss.textContent = '不使用'; dismiss.onclick = () => updateResearchStatus(record.id, 'dismissed'); actions.append(dismiss); } list.append(card); }); }
async function saveAndAssessResearch() { const button = $('#research-assess'); busy(button, true, '正在入库...'); try { const payload = researchPayload(); const stored = app.editingResearchId ? await api(`/api/research/${app.editingResearchId}`, { method: 'PUT', body: JSON.stringify(payload) }) : await api('/api/research', { method: 'POST', body: JSON.stringify(payload) }); app.editingResearchId = stored.research.id; setResearchState('AI 正在预审...'); const assessed = await api(`/api/research/${stored.research.id}/assess`, { method: 'POST', body: '{}' }); fillResearch(assessed.research); await refreshResearch(); toast(`资料已预审：${statusLabel(assessed.research.status)}`); } catch (error) { setResearchState('预审失败'); toast(error.message); } finally { busy(button, false, ''); } }
async function updateResearchStatus(id, status) { try { await api(`/api/research/${id}/status`, { method: 'POST', body: JSON.stringify({ status }) }); await refreshResearch(); } catch (error) { toast(error.message); } }
function renderDiscovery(candidates) { const root = $('#discovery-results'); root.replaceChildren(); if (!candidates.length) { root.innerHTML = '<p class="empty-copy">没有发现适合的候选资料。换一个更具体的公司、岗位或主题再试。</p>'; return; } candidates.forEach(candidate => { const card = document.createElement('article'); card.className = 'discovery-item'; card.innerHTML = '<a target="_blank" rel="noreferrer"></a><p></p><div><span></span><button class="secondary-button compact-button" type="button">带入资料库</button></div>'; const screening = candidate.screening || {}; card.querySelector('a').href = candidate.url; card.querySelector('a').textContent = candidate.title; card.querySelector('p').textContent = `${candidate.summary || '候选公开资料'}${screening.reason ? ` · 初筛：${screening.reason}` : ''}`; card.querySelector('span').textContent = [candidate.platform, candidate.published_date, screening.relevance != null ? `相关度提示 ${screening.relevance}/100` : ''].filter(Boolean).join(' · ') || '公开搜索结果'; card.querySelector('button').onclick = () => { resetResearch(); $('#research-title').value = candidate.title; $('#research-url').value = candidate.url; $('#research-platform').value = ['牛客', '小红书'].includes(candidate.platform) ? candidate.platform : '其他'; $('#research-company').value = $('#discover-company').value; $('#research-role').value = $('#discover-role').value || '产品经理'; $('#research-round').value = $('#discover-round').value; $('#research-date').value = candidate.published_date || ''; $('#research-notes').value = `搜索预览：${candidate.summary || ''}`; $('#research-source').focus(); }; root.append(card); }); }
function renderSearchMeta(meta) {
  const root = $('#search-meta');
  root.replaceChildren();
  root.hidden = !meta;
  if (!meta) return;
  const title = document.createElement('strong'); title.textContent = `${meta.platform_label || '全网'} · 已尝试 ${meta.queries_tried?.length || 0} 条查询 · 候选 ${meta.result_count || 0}`; root.append(title);
  (meta.queries_tried || []).slice(0, 3).forEach(query => { const item = document.createElement('span'); item.textContent = query; root.append(item); });
  if (meta.empty_reason) { const reason = document.createElement('p'); reason.textContent = `${meta.empty_reason} 可以换同义词，或手动粘贴小红书原帖链接。`; root.append(reason); }
}

function renderDiscovery(candidates) {
  const root = $('#discovery-results'); root.replaceChildren();
  if (!candidates?.length) { root.innerHTML = '<p class="empty-copy">没有发现通过来源校验的候选资料。结果稀疏时请换主题、轮次或手动粘贴原帖。</p>'; return; }
  candidates.forEach(candidate => {
    const card = document.createElement('article'); card.className = 'discovery-item'; card.innerHTML = '<a target="_blank" rel="noreferrer"></a><p></p><div><span></span><button class="secondary-button compact-button" type="button">带入资料库</button></div>';
    const screening = candidate.screening || {};
    card.querySelector('a').href = candidate.url; card.querySelector('a').textContent = candidate.title;
    card.querySelector('p').textContent = `${candidate.summary || '候选公开资料'}${screening.reason ? ` · 初筛：${screening.reason}` : ''}`;
    const breakdown = screening.relevance_breakdown ? Object.entries(screening.relevance_breakdown).map(([key, value]) => `${key} ${value}`).join(' / ') : '';
    const fetchLabel = candidate.fetch_status === 'fetched_metadata' ? '已自动读取公开页' : candidate.fetch_status === 'shell_only' ? '页面仅返回脚本壳' : candidate.fetch_status === 'blocked' ? '页面拒绝读取' : '需人工确认';
    card.querySelector('span').textContent = [candidate.platform, candidate.published_date, candidate.platform_id ? `来源 ${candidate.platform_id}` : '', screening.relevance != null ? `相关度提示 ${screening.relevance}/100` : '', breakdown, fetchLabel].filter(Boolean).join(' · ') || '公开搜索结果';
  card.querySelector('button').onclick = () => importResearchCandidate(candidate);
    root.append(card);
  });
}
async function importResearchCandidate(candidate) { try { const data = await api('/api/research/candidate', { method: 'POST', body: JSON.stringify({ candidate }) }); fillResearch(data.research); await refreshResearch(); setView('research-view'); $('#research-source').focus(); toast(data.existing ? '候选已存在，已自动回填。' : '候选已自动收录，标题、链接和平台已回填；请补充原帖正文。'); } catch (error) { toast(error.message); } }

 async function discoverResearch(event) { event.preventDefault(); const button = $('#discover-button'); busy(button, true, 'Gemini 正在搜索...'); try { const payload = { company: $('#discover-company').value, role: $('#discover-role').value, round_name: $('#discover-round').value, topic: $('#discover-topic').value, platform: $('#discover-platform').value, job_description: field('job_description').value, jd_analysis: app.jdAnalysis }; const data = await api('/api/research/discover', { method: 'POST', body: JSON.stringify(payload) }); app.researchCandidates = data.candidates || []; renderSearchMeta(data.search_meta); renderDiscovery(data.candidates); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
 async function runResearchAgent() { const button = $('#agent-button'); busy(button, true, 'Agent 正在自主调研...'); try { const payload = { company: $('#discover-company').value, role: $('#discover-role').value, round_name: $('#discover-round').value, topic: $('#discover-topic').value, platform: $('#discover-platform').value, job_description: field('job_description').value, jd_analysis: app.jdAnalysis }; const data = await api('/api/research/agent', { method: 'POST', body: JSON.stringify(payload) }); app.researchCandidates = data.collected || []; renderSearchMeta(data.search_meta); renderAgentTrace(data.trace, data.stop_reason, data.found_enough); renderDiscovery(data.collected || []); await autoIngestResearchCandidates(app.researchCandidates); } catch (error) { toast(error.message); } finally { busy(button, false, ''); } }
function renderAgentTrace(trace, stopReason, foundEnough) { const root = $('#agent-trace'); root.replaceChildren(); root.hidden = !(trace && trace.length); if (!trace || !trace.length) return; trace.forEach(step => { const card = document.createElement('div'); card.className = 'agent-round'; card.innerHTML = '<strong></strong><p></p><p class="agent-query"></p>'; const label = step.action === 'stop' ? '停止' : step.action === 'fetch' ? '读取公开页' : '搜索'; card.querySelector('strong').textContent = `第 ${step.round} 轮 · ${label}${step.action === 'search' ? ` · 新增 ${step.added || 0}` : ''}${step.action === 'fetch' ? ` · 读取 ${step.fetched || 0}` : ''}`; card.querySelector('p').textContent = step.reasoning || ''; const q = card.querySelector('.agent-query'); if (step.query) q.textContent = `${step.action === 'fetch' ? '动作' : '查询词'}：${step.query}`; else q.remove(); root.append(card); }); const stop = document.createElement('p'); stop.className = 'agent-stop'; stop.textContent = `${foundEnough ? '已找够待确认资料' : '未达目标数量'} · ${stopReason || '结束'}`; root.append(stop); }

const TREND_LABELS = { improving: '↑ 改进中', declining: '↓ 下滑', stable: '→ 持平', insufficient_data: '样本不足' };
function renderMemory(memory) { const root = $('#memory-summary'); root.replaceChildren(); const items = [{ label: '已复盘面试', value: memory.reviewed_interviews || 0 }, { label: '待完成行动', value: memory.open_actions?.length || 0 }, { label: '重复薄弱点', value: memory.recurring_gaps?.length || 0 }]; items.forEach(item => { const block = document.createElement('div'); block.innerHTML = '<span></span><strong></strong>'; block.querySelector('span').textContent = item.label; block.querySelector('strong').textContent = item.value; root.append(block); }); const patterns = document.createElement('div'); patterns.className = 'memory-patterns'; if (memory.stage === 'cold_start') { const n = memory.interviews_to_unlock_trend || 0; patterns.innerHTML = '<p>跨场成长趋势</p>'; const hint = document.createElement('span'); hint.className = 'cold-start-hint'; hint.textContent = n > 0 ? `再完成 ${n} 场复盘即可解锁跨场成长趋势` : '再完成 1 场复盘即可解锁跨场成长趋势'; patterns.append(hint); } else { patterns.innerHTML = '<p>当前重复出现</p>'; (memory.recurring_gaps || []).slice(0, 4).forEach(item => { const tag = document.createElement('span'); tag.textContent = `${item.title} · ${item.occurrences}次`; patterns.append(tag); }); if (!(memory.recurring_gaps || []).length) patterns.append('暂无足够数据'); const trends = (memory.skill_summary || []).filter(s => s.trend && s.trend !== 'insufficient_data'); if (trends.length) { const trendBox = document.createElement('div'); trendBox.className = 'memory-trends'; trendBox.innerHTML = '<p>能力趋势</p>'; trends.slice(0, 6).forEach(s => { const tag = document.createElement('span'); tag.className = `trend-${s.trend}`; tag.textContent = `${s.skill_id} · ${TREND_LABELS[s.trend] || s.trend}`; trendBox.append(tag); }); patterns.append(trendBox); } } root.append(patterns); }
function renderSkillList(skills) { const root = $('#skill-list'); root.replaceChildren(); skills.forEach(skill => { const item = document.createElement('div'); item.className = 'skill-definition'; item.innerHTML = '<strong></strong><span></span>'; item.querySelector('strong').textContent = skill.name; const anchors = skill.score_anchors || {}; item.querySelector('span').textContent = `${skill.focus} 评分锚点：1 ${anchors['1'] || '未展示'}；3 ${anchors['3'] || '合格'}；5 ${anchors['5'] || '优秀'}`; root.append(item); }); }
function renderGrowthReport(report) { const root = $('#growth-content'); root.replaceChildren(); root.hidden = !report; $('#growth-empty').hidden = !!report; if (!report) return; const summary = document.createElement('div'); summary.className = 'review-summary'; summary.textContent = report.summary; root.append(summary); const assessment = reviewSection('阶段判断'); const assessmentText = document.createElement('p'); assessmentText.className = 'body-copy'; assessmentText.textContent = report.stage_assessment; assessment.append(assessmentText); root.append(assessment); renderCoachItems(root, '可观察到的变化', report.growth_signals, 'interpretation'); if (report.recurring_patterns?.length) { const section = reviewSection('持续模式'); const list = document.createElement('div'); list.className = 'pattern-list'; report.recurring_patterns.forEach(pattern => { const row = document.createElement('article'); row.innerHTML = '<strong></strong><span></span><p></p><p class="next"></p>'; row.querySelector('strong').textContent = pattern.skill; row.querySelector('span').textContent = `${pattern.occurrences} 次`; row.querySelector('p').textContent = `证据：${pattern.evidence}`; row.querySelector('.next').textContent = pattern.recommendation; list.append(row); }); section.append(list); root.append(section); } if (report.priority_training?.length) { const section = reviewSection('最高优先级训练'); const list = document.createElement('div'); list.className = 'training-list'; report.priority_training.forEach(item => { const row = document.createElement('article'); row.innerHTML = '<strong></strong><p></p><p class="next"></p>'; row.querySelector('strong').textContent = item.action; row.querySelector('p').textContent = item.why_now; row.querySelector('.next').textContent = `验收标准：${item.success_criterion}`; list.append(row); }); section.append(list); root.append(section); } const quality = reviewSection('数据边界'); const qualityText = document.createElement('p'); qualityText.className = 'body-copy'; qualityText.textContent = report.data_quality; quality.append(qualityText); root.append(quality); }
async function refreshGrowthMemory() { try { const data = await api('/api/growth-memory'); renderMemory(data.memory); $('#growth-state').textContent = data.memory.reviewed_interviews ? '已有记录' : '等待数据'; } catch (error) { toast(error.message); } }
async function generateGrowth() { const button = $('#generate-growth'); busy(button, true, 'Gemini 正在汇总...'); $('#growth-state').textContent = '正在分析'; try { const snapshot = await api('/api/growth-memory'); renderMemory(snapshot.memory); if (snapshot.memory.stage === 'cold_start') { const n = snapshot.memory.interviews_to_unlock_trend || 1; $('#growth-state').textContent = '样本不足'; toast(`样本不足：再完成 ${n} 场复盘即可生成跨场成长报告。`); return; } const data = await api('/api/growth-report', { method: 'POST', body: '{}' }); renderMemory(data.memory); renderGrowthReport(data.report); $('#growth-state').textContent = '已生成'; } catch (error) { $('#growth-state').textContent = '生成失败'; toast(error.message); } finally { busy(button, false, ''); } }

interviewForm.onsubmit = async event => { event.preventDefault(); try { await saveInterview(); } catch (error) { toast(error.message); } };
$('#new-interview').onclick = resetInterview;
$('#load-demo').onclick = async () => { try { const data = await api('/api/interviews/demo', { method: 'POST', body: '{}' }); await refreshInterviews(); await loadInterview(data.interview.id); } catch (error) { toast(error.message); } };
$('#review-button').onclick = reviewInterview; $('#extract-jd').onclick = extractJd; $('#transcribe-audio').onclick = transcribe; $('#resume-select').onchange = selectResume; $('#note-questions').onclick = generateNoteQuestions;
$('#audio-file').onchange = event => { app.selectedAudio = event.target.files?.[0] || null; $('#audio-state').textContent = app.selectedAudio ? `${app.selectedAudio.name} · ${(app.selectedAudio.size / 1024 / 1024).toFixed(1)} MB` : '尚未选择录音'; };
$('#transcript-file').onchange = async event => { const file = event.target.files?.[0]; if (!file) return; if (file.size > 32000) { toast('文本文件超过 32 KB，请只导入本轮相关片段。'); return; } field('transcript').value = await file.text(); setSaveState('有未保存修改'); };
interviewFields.forEach(name => field(name).addEventListener('input', () => { if (name === 'job_description') app.jdAnalysis = null; setSaveState('有未保存修改'); }));
$('#new-resume').onclick = resetResume; $('#resume-form').onsubmit = event => { event.preventDefault(); saveResume(); }; $('#resume-file').onchange = event => { app.selectedResumeFile = event.target.files?.[0] || null; $('#resume-file-state').textContent = app.selectedResumeFile ? `${app.selectedResumeFile.name} · ${(app.selectedResumeFile.size / 1024 / 1024).toFixed(1)} MB` : '尚未选择文件'; }; $('#parse-resume-file').onclick = parseResumeFile;
$('#research-new').onclick = resetResearch; $('#research-form').onsubmit = event => { event.preventDefault(); saveAndAssessResearch(); }; $('#discover-form').onsubmit = discoverResearch; $('#agent-button').onclick = runResearchAgent; $('#generate-growth').onclick = generateGrowth; $('#open-jd-research').onclick = () => setView('research-view');
$$('[data-view]').forEach(button => button.onclick = () => setView(button.dataset.view));
$$('button').forEach(button => button.dataset.label = button.textContent);
async function initializeApp() { resetInterview(); await Promise.all([refreshResumes(), refreshInterviews(), refreshResearch(), refreshGrowthMemory(), api('/api/skills').then(data => renderSkillList(data.skills))]); try { const data = await api('/api/health'); const backup = Math.max(0, (data.providers || []).length - 1); const demoTag = data.demo_mode && !data.can_write ? ' · 只读演示' : ''; $('#model-status').textContent = `${data.active_provider || 'gemini'} · ${data.model}${backup ? ` · ${backup} 个备用` : ''}${demoTag}`; $('.status-dot').className = 'status-dot ready'; } catch { $('#model-status').textContent = '模型未配置'; $('.status-dot').className = 'status-dot error'; } }
function showLogin(message = '') { $('#login-gate').hidden = false; $('#login-error').hidden = !message; $('#login-error').textContent = message; $('#access-token').focus(); }
$('#login-form').onsubmit = async event => { event.preventDefault(); const button = $('#login-button'); busy(button, true, '正在验证...'); sessionStorage.setItem(ACCESS_TOKEN_KEY, $('#access-token').value); try { await initializeApp(); $('#login-gate').hidden = true; $('#login-error').hidden = true; } catch (error) { sessionStorage.removeItem(ACCESS_TOKEN_KEY); showLogin(error.message); } finally { busy(button, false, ''); } };
(async () => { try { await initializeApp(); } catch (error) { if (error.message === '需要访问口令。') showLogin(); else toast(error.message); } })();
